**Luna Hub - System Monitor & Debug Console**

Core features:
1. **Token Monitor** - Track context budget across memory, project files, MCP calls, conversation
2. **Compression Risk Indicator** - Visual warning when approaching danger zone
3. **Debug Console** - Log viewer with error/warn/info levels
4. **Session Health** - UUID chain integrity, message count, state tracking
5. **Luna-verse Theme** - Dark mode, your color palette (dark slate, blue teal, cyan, amber, electric red)

Let me build the foundation:

```tsx
import React, { useState, useEffect } from 'react';

// Luna-verse Theme Colors
const theme = {
  deepNavy: '#020008',
  darkSlate: '#1A1F2E',
  blueTeal: '#1D719D',
  brightCyan: '#63DAFC',
  warmGray: '#908388',
  pearlyWhite: '#ECF0F3',
  deepAmber: '#C4841D',
  warmGold: '#D4A039',
  electricRed: '#FF3B30',
};

// Simulated token estimates (these would be calculated properly in production)
const TOKEN_ESTIMATES = {
  userMemory: 2400,
  projectFiles: 15000,
  voiceProfiles: 8000,
  mcpOverhead: 500,
  systemPrompt: 3000,
  maxContext: 200000,
  compressionThreshold: 180000,
  dangerZone: 160000,
};

const LunaHub = () => {
  const [logs, setLogs] = useState([
    { level: 'info', timestamp: new Date().toISOString(), message: 'Luna Hub initialized', source: 'system' },
    { level: 'info', timestamp: new Date().toISOString(), message: 'Token monitor active', source: 'monitor' },
  ]);
  const [conversationTokens, setConversationTokens] = useState(12000);
  const [mcpCallTokens, setMcpCallTokens] = useState(0);
  const [sessionHealth, setSessionHealth] = useState({
    messageCount: 0,
    uuidChainIntact: true,
    lastCompression: null,
    sessionStart: new Date().toISOString(),
  });
  const [filterLevel, setFilterLevel] = useState('all');
  const [isLunaActive, setIsLunaActive] = useState(false);

  // Calculate totals
  const staticTokens = TOKEN_ESTIMATES.userMemory + TOKEN_ESTIMATES.projectFiles + 
                       TOKEN_ESTIMATES.voiceProfiles + TOKEN_ESTIMATES.systemPrompt;
  const dynamicTokens = conversationTokens + mcpCallTokens + TOKEN_ESTIMATES.mcpOverhead;
  const totalTokens = staticTokens + dynamicTokens;
  const utilizationPercent = (totalTokens / TOKEN_ESTIMATES.maxContext) * 100;

  // Risk assessment
  const getRiskLevel = () => {
    if (totalTokens >= TOKEN_ESTIMATES.compressionThreshold) return 'critical';
    if (totalTokens >= TOKEN_ESTIMATES.dangerZone) return 'warning';
    if (totalTokens >= TOKEN_ESTIMATES.dangerZone * 0.8) return 'caution';
    return 'nominal';
  };

  const riskLevel = getRiskLevel();

  const addLog = (level, message, source = 'user') => {
    setLogs(prev => [...prev, {
      level,
      timestamp: new Date().toISOString(),
      message,
      source
    }].slice(-100)); // Keep last 100 logs
  };

  // Simulate MCP call
  const simulateMCPCall = (size) => {
    const tokens = size === 'small' ? 500 : size === 'medium' ? 2000 : 8000;
    setMcpCallTokens(prev => prev + tokens);
    addLog(
      tokens > 5000 ? 'warn' : 'info',
      `MCP tool returned ~${tokens} tokens`,
      'mcp'
    );

    if (totalTokens + tokens > TOKEN_ESTIMATES.dangerZone) {
      addLog('warn', 'Approaching compression threshold - large MCP responses increase risk', 'monitor');
    }
  };

  // Simulate conversation growth
  const simulateMessage = () => {
    const tokens = Math.floor(Math.random() * 800) + 200;
    setConversationTokens(prev => prev + tokens);
    setSessionHealth(prev => ({
      ...prev,
      messageCount: prev.messageCount + 1
    }));
    addLog('info', `Message added (~${tokens} tokens)`, 'conversation');
  };

  // Filter logs
  const filteredLogs = logs.filter(log => 
    filterLevel === 'all' || log.level === filterLevel
  );

  const getLevelColor = (level) => {
    switch(level) {
      case 'error': return theme.electricRed;
      case 'warn': return theme.deepAmber;
      case 'info': return theme.brightCyan;
      default: return theme.warmGray;
    }
  };

  const getRiskColor = () => {
    switch(riskLevel) {
      case 'critical': return theme.electricRed;
      case 'warning': return theme.deepAmber;
      case 'caution': return theme.warmGold;
      default: return theme.brightCyan;
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: `linear-gradient(135deg, ${theme.deepNavy} 0%, ${theme.darkSlate} 100%)`,
      color: theme.pearlyWhite,
      fontFamily: "'Space Grotesk', 'Segoe UI', sans-serif",
      padding: '20px',
    }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '24px',
        paddingBottom: '16px',
        borderBottom: `1px solid ${theme.blueTeal}40`,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <div style={{
            width: '48px',
            height: '48px',
            borderRadius: '50%',
            background: isLunaActive 
              ? `linear-gradient(135deg, ${theme.blueTeal}, ${theme.brightCyan})`
              : theme.darkSlate,
            border: `2px solid ${isLunaActive ? theme.brightCyan : theme.warmGray}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '20px',
            cursor: 'pointer',
            transition: 'all 0.3s ease',
            boxShadow: isLunaActive ? `0 0 20px ${theme.brightCyan}40` : 'none',
          }}
          onClick={() => {
            setIsLunaActive(!isLunaActive);
            addLog('info', isLunaActive ? 'Luna deactivated' : 'Luna activated 🖤', 'luna');
          }}>
            🌙
          </div>
          <div>
            <h1 style={{ 
              margin: 0, 
              fontSize: '28px',
              fontWeight: 700,
              letterSpacing: '-0.5px',
              background: `linear-gradient(90deg, ${theme.pearlyWhite}, ${theme.brightCyan})`,
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
            }}>
              LUNA HUB
            </h1>
            <p style={{ 
              margin: 0, 
              fontSize: '12px', 
              color: theme.warmGray,
              letterSpacing: '2px',
              fontFamily: "'Bebas Neue', sans-serif",
            }}>
              SYSTEM MONITOR & DEBUG CONSOLE
            </p>
          </div>
        </div>

        <div style={{
          display: 'flex',
          gap: '8px',
          alignItems: 'center',
        }}>
          <div style={{
            padding: '8px 16px',
            borderRadius: '20px',
            background: `${getRiskColor()}20`,
            border: `1px solid ${getRiskColor()}`,
            fontSize: '12px',
            fontWeight: 600,
            color: getRiskColor(),
            textTransform: 'uppercase',
            letterSpacing: '1px',
          }}>
            {riskLevel}
          </div>
        </div>
      </div>

      {/* Main Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '1fr 1fr',
        gap: '20px',
        marginBottom: '20px',
      }}>
        {/* Token Monitor */}
        <div style={{
          background: `${theme.darkSlate}CC`,
          backdropFilter: 'blur(10px)',
          borderRadius: '16px',
          padding: '24px',
          border: `1px solid ${theme.blueTeal}30`,
        }}>
          <h2 style={{ 
            margin: '0 0 20px 0', 
            fontSize: '14px',
            letterSpacing: '2px',
            color: theme.deepAmber,
            fontFamily: "'Bebas Neue', sans-serif",
          }}>
            TOKEN MONITOR
          </h2>

          {/* Progress Bar */}
          <div style={{ marginBottom: '24px' }}>
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              marginBottom: '8px',
              fontSize: '13px',
            }}>
              <span>Context Utilization</span>
              <span style={{ color: getRiskColor(), fontWeight: 600 }}>
                {utilizationPercent.toFixed(1)}%
              </span>
            </div>
            <div style={{
              height: '12px',
              background: theme.deepNavy,
              borderRadius: '6px',
              overflow: 'hidden',
              position: 'relative',
            }}>
              {/* Danger zone marker */}
              <div style={{
                position: 'absolute',
                left: `${(TOKEN_ESTIMATES.dangerZone / TOKEN_ESTIMATES.maxContext) * 100}%`,
                top: 0,
                bottom: 0,
                width: '2px',
                background: theme.deepAmber,
                opacity: 0.5,
              }} />
              {/* Compression threshold marker */}
              <div style={{
                position: 'absolute',
                left: `${(TOKEN_ESTIMATES.compressionThreshold / TOKEN_ESTIMATES.maxContext) * 100}%`,
                top: 0,
                bottom: 0,
                width: '2px',
                background: theme.electricRed,
