            </div>
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              marginTop: '4px',
              fontSize: '11px',
              color: theme.warmGray,
            }}>
              <span>0</span>
              <span>{(totalTokens / 1000).toFixed(1)}K / {(TOKEN_ESTIMATES.maxContext / 1000)}K</span>
            </div>
          </div>

          {/* Token Breakdown */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {[
              { label: 'User Memory', value: TOKEN_ESTIMATES.userMemory, color: theme.blueTeal },
              { label: 'Project Files', value: TOKEN_ESTIMATES.projectFiles, color: theme.brightCyan },
              { label: 'Voice Profiles', value: TOKEN_ESTIMATES.voiceProfiles, color: theme.warmGold },
              { label: 'System Prompt', value: TOKEN_ESTIMATES.systemPrompt, color: theme.warmGray },
              { label: 'Conversation', value: conversationTokens, color: theme.deepAmber },
              { label: 'MCP Responses', value: mcpCallTokens, color: theme.electricRed },
            ].map(item => (
              <div key={item.label} style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                padding: '8px 12px',
                background: `${item.color}10`,
                borderRadius: '8px',
