                  {(item.value / 1000).toFixed(1)}K
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Session Health */}
        <div style={{
          background: `${theme.darkSlate}CC`,
          backdropFilter: 'blur(10px)',
          borderRadius: '16px',
          padding: '24px',
          border: `1px solid ${theme.blueTeal}30`,
        }}>
          <h2 style={{ 
            margin: '0 0 20px 0', 
            fontSize: '14px',
            letterSpacing: '2px',
            color: theme.deepAmber,
            fontFamily: "'Bebas Neue', sans-serif",
          }}>
