            }}>
              COMPRESSION RISK
            </div>
            <div style={{
              display: 'flex',
              gap: '4px',
              marginBottom: '8px',
            }}>
              {[...Array(10)].map((_, i) => {
                const threshold = (i + 1) * 10;
                const filled = utilizationPercent >= threshold * 0.8;
