              {riskLevel === 'nominal' && '✓ Operating within safe parameters'}
            </div>
          </div>

          {/* Quick Actions */}
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            <button 
              onClick={simulateMessage}
