const exportLogs = (format = 'json') => {
  const data = format === 'json' 
    ? JSON.stringify(logs, null, 2)
    : logs.map(l => `[${l.timestamp}] ${l.level.toUpperCase()} [${l.source}] ${l.message}`).join('\n');

