### 4. State Machine Visualization
**Location:** New panel/tab - could be collapsible section or separate view

**Implementation:**

**State definition:**
```js
const STATES = {
  IDLE: 'idle',
  COMPOSING: 'composing',
  GENERATING: 'generating',
  EDITING: 'editing',
  REVIEWING: 'reviewing',
  PUBLISHING: 'publishing',
};

const TRANSITIONS = {
  [STATES.IDLE]: [STATES.COMPOSING],
  [STATES.COMPOSING]: [STATES.GENERATING, STATES.IDLE],
  [STATES.GENERATING]: [STATES.EDITING, STATES.COMPOSING],
  [STATES.EDITING]: [STATES.REVIEWING, STATES.GENERATING],
  [STATES.REVIEWING]: [STATES.PUBLISHING, STATES.EDITING],
  [STATES.PUBLISHING]: [STATES.IDLE],
};

const [currentState, setCurrentState] = useState(STATES.IDLE);
const [stateHistory, setStateHistory] = useState([]);
```

